module top_module(
	input clk,
	input load,
	input [7:0] data_in,
	output [7:0] out);reg [7:0] unused_shift_reg;

	always @(posedge clk) begin
		if (load)
			unused_shift_reg <= data_in;
		else
			unused_shift_reg <= {unused_shift_reg[6:0], 1'b0};
	end

	assign out = unused_shift_reg;

endmodule
